//
//  XPBluetoothManager.h
//  XiaoPengQiChe
//
//  Created by Ajzonic on 2018/11/12.
//  Copyright © 2018年 xiaopeng.com. All rights reserved.
//

#import <Foundation/Foundation.h>
#import "BabyBluetooth/BabyBluetooth.h"

typedef NS_ENUM(int64_t, XPBluetoothCentralState) {
    XPBlueToothCentralUnknown         = CBManagerStateUnknown,
    XPBlueToothCentralResetting       = CBManagerStateResetting,
    XPBlueToothCentralUnsupported     = CBManagerStateUnsupported,
    XPBlueToothCentralUnauthorized    = CBManagerStateUnauthorized,
    XPBlueToothCentralPoweredOff      = CBManagerStatePoweredOff,
    XPBlueToothCentralPoweredOn       = CBManagerStatePoweredOn,
};

@interface XPBluetoothConnectInfo : NSObject
{
    dispatch_semaphore_t _lock;
    CBPeripheral* _peripheral;
}
@property (nonatomic,strong,setter=setupPeripheral:,getter=getPeripheral) CBPeripheral* peripheral;
@property (nonatomic,strong) NSString* peripheralName;
@property (nonatomic,strong) NSDictionary* advertisementData;
@property (nonatomic,strong) NSArray<CBUUID*>* serviceUUIDs;
@property (nonatomic,strong) NSArray<CBUUID*>* characteristicsUUIDs;
@property (nonatomic,strong) NSString* positionName; // 由外部传入（主、左、右、后）

- (BOOL)discoverFilter:(NSString*)peripheralName advertisementData:(NSDictionary*)advertisementData RSSI:(NSNumber*)RSSI;
- (BOOL)connectFilter:(NSString*)peripheralName advertisementData:(NSDictionary*)advertisementData RSSI:(NSNumber*)RSSI;
@end

NS_INLINE NSString* CBCharacteristicPropertiesToString(CBCharacteristicProperties p) {
    NSMutableArray* array = [NSMutableArray arrayWithCapacity:12];
    if (p&CBCharacteristicPropertyBroadcast) {
        [array addObject:@"CBCharacteristicPropertyBroadcast"];
    }

    if (p&CBCharacteristicPropertyRead) {
        [array addObject:@"CBCharacteristicPropertyRead"];
    }

    if (p&CBCharacteristicPropertyWriteWithoutResponse) {
        [array addObject:@"CBCharacteristicPropertyWriteWithoutResponse"];
    }

    if (p&CBCharacteristicPropertyWrite) {
        [array addObject:@"CBCharacteristicPropertyWrite"];
    }

    if (p&CBCharacteristicPropertyNotify) {
        [array addObject:@"CBCharacteristicPropertyNotify"];
    }

    if (p&CBCharacteristicPropertyIndicate) {
        [array addObject:@"CBCharacteristicPropertyIndicate"];
    }

    if (p&CBCharacteristicPropertyAuthenticatedSignedWrites) {
        [array addObject:@"CBCharacteristicPropertyAuthenticatedSignedWrites"];
    }

    if (p&CBCharacteristicPropertyExtendedProperties) {
        [array addObject:@"CBCharacteristicPropertyExtendedProperties"];
    }

    if (p&CBCharacteristicPropertyExtendedProperties) {
        [array addObject:@"CBCharacteristicPropertyExtendedProperties"];
    }

    if (p&CBCharacteristicPropertyNotifyEncryptionRequired) {
        [array addObject:@"CBCharacteristicPropertyNotifyEncryptionRequired"];
    }
    if (p&CBCharacteristicPropertyIndicateEncryptionRequired) {
        [array addObject:@"CBCharacteristicPropertyIndicateEncryptionRequired"];
    }

    return [array componentsJoinedByString:@"|"];
}

NS_INLINE NSString* NSStringFromCBPeripheralState(CBPeripheralState state) {
    switch (state) {
        case CBPeripheralStateDisconnected:
            return @"CBPeripheralStateDisconnected";
            break;
        case CBPeripheralStateConnecting:
            return @"CBPeripheralStateConnecting";
            break;
        case CBPeripheralStateConnected:
            return @"CBPeripheralStateConnected";
            break;
        case CBPeripheralStateDisconnecting:
            return @"CBPeripheralStateDisconnecting";
            break;
        default:
            break;
    }

    return @"Unknow";
}

NS_INLINE NSString* NSStringFromXPBluetoothCentralState(XPBluetoothCentralState state) {
    switch (state) {
        case XPBlueToothCentralUnknown:
            return @"XPBlueToothCentralUnknown";
            break;
        case XPBlueToothCentralResetting:
            return @"XPBlueToothCentralResetting";
            break;
        case XPBlueToothCentralUnsupported:
            return @"XPBlueToothCentralUnsupported";
            break;
        case XPBlueToothCentralUnauthorized:
            return @"XPBlueToothCentralUnauthorized";
            break;
        case XPBlueToothCentralPoweredOff:
            return @"XPBlueToothCentralPoweredOff";
            break;
        case XPBlueToothCentralPoweredOn:
            return @"XPBlueToothCentralPoweredOn";
            break;
        default:
            break;
    }
    return @"XPBlueToothCentralUnknown";
}

@interface XPBluetoothManager : NSObject

@property (nonatomic,assign,readonly) XPBluetoothCentralState centralState;
@property (nonatomic,assign,readonly) BOOL isScanning;
@property (nonatomic,strong,readonly) RACSubject<NSDictionary*>* notifySubject;
@property (nonatomic,strong,readonly) RACSubject<NSDictionary*>* disconnectSubject;
@property (nonatomic,strong,readonly) RACSubject<NSDictionary*>* connectSubject;
@property (nonatomic,strong,readonly) RACSubject<NSDictionary*>* readSubject;
@property (nonatomic,strong,readonly) RACSubject<NSDictionary*>* sendSubject;
@property (nonatomic,strong,readonly) RACSubject<id>* discoveryPeripheralSubject;
@property (nonatomic,strong,readonly) RACSubject<NSDictionary*>* discoveryServiceSubject;
@property (nonatomic,strong,readonly) RACSubject<NSDictionary*>* discoveryCharacteristicSubject;

@property (nonatomic, assign) BOOL useScanUUIDs;

+ (instancetype)manager;

- (BOOL)safeCheckCentralState:(const XPBluetoothCentralState)state;

- (CBPeripheral*)retrievePeripheralsWithIdentifiers:(NSUUID*)uuid;

- (void)connect:(XPBluetoothConnectInfo*)connectInfo;

- (void)requestValueWithUUID:(NSString*)uuid peripheral:(CBPeripheral*)peripheral;

- (void)send:(NSData*)data UUID:(NSString*)uuid peripheral:(CBPeripheral*)peripheral;

- (void)notifyWithUUID:(NSString*)uuid peripheral:(CBPeripheral*)peripheral;

- (void)disconnect:(CBPeripheral*)peripheral;

- (void)forceDisconnect:(CBPeripheral*)peripheral;

- (void)cancelScan;

- (BOOL)peripheralIsConnected:(CBPeripheral *)peripheral;

- (void)cancelNotifyWithUUID:(NSString*)uuid peripheral:(CBPeripheral*)peripheral;

/// 初始化BabyBluetooth，以设置状态监听等
- (void)initBabyBluetoothIfNeed;

///  清理车辆BLE信息
- (void)clearCarBLEInfo;

/// 取消所有在途连接，终止扫描，并清理所有BLE信息（clearCarBLEInfo）
- (void)cancelAndClear;

@end

