import Foundation
import CoreBluetooth
import Combine

class BleCentral: NSObject {

    var centralManager: CentralManager?
    var option: CentralManager.CentralManagerOptions?
    var cancellable: AnyCancellable?
    @Published var bleState: CBManagerState = .unknown
    let writeLock = DispatchSemaphore(value: 1)

    var isInitialized: Bool = false

    static let shared = BleCentral()

    private override init() {
        super.init()
    }

    @discardableResult
    func start() -> CentralManager {
        writeLock.wait()
        guard centralManager == nil else {
            writeLock.signal()
            return centralManager!
        }

        let showPowerAlert = AppRunState.shared.isInBackground == false && AppRunState.shared.isInVehicleControlPage

        let restoreIdentifier = "XPVehicleSDK.restoreIdentifier"

        let backgroundModes = Bundle.main.infoDictionary?["UIBackgroundModes"]
        if let backgroundModes = backgroundModes as? [String], backgroundModes.contains("bluetooth-central") {
            //后台模式
            option = CentralManager.CentralManagerOptions(showPowerAlert: showPowerAlert, restoreIdentifier: restoreIdentifier)
        }
        else {
            //非后台模式
            option = CentralManager.CentralManagerOptions(showPowerAlert: showPowerAlert)
        }
        var cm = CentralManager.live(options: option)
        self.centralManager = cm
        cancellable = self.centralManager?.didUpdateState
            .sink { [weak self] state in
                guard let self = self else { return }
                self.isInitialized = true
                self.bleState = state
            }

        bleState = self.centralManager?.state ?? .unknown
        writeLock.signal()

