import Foundation


@objc(XPMQTTConnectionState)
public enum MQTTConnectionState : Int, CustomStringConvertible {

    case NotConnected = 0       // 未连接
    case Connecting = 1         // 连接中
    case Available = 2          // 连接已可用

    public var name: String {
        switch self {
        case .NotConnected: return "NotConnected"
        case .Connecting: return "Connecting"
        case .Available: return "Available"

        default: return "Unknown"
        }
    }

    public var description: String {
        return "MQTTConnectionState:(\(rawValue)) ." + name
    }
}

@objc(XPBLEConnectionState)
public enum BLEConnectionState : Int, CustomStringConvertible {

    case NotConnected = 0       // 未连接
    case Scanning               // 扫描中
    case Connecting             // 连接中
    case Available              // 连接已可用

    public var name: String {
        switch self {
        case .NotConnected: return "NotConnected"
        case .Connecting: return "Connecting"
        case .Available: return "Available"
        case .Scanning: return "Scanning"

        default: return "Unknown"
        }
    }

    public var description: String {
        return "BLEConnectionState:(\(rawValue)) ." + name
    }
}

@objc(XPBLESysState)
public enum BLESysState : Int, CustomStringConvertible {

    case Unknown = 0            // 未知状态
    case Resetting = 1          //
    case Unsupported = 2        // 设备不支持蓝牙
    case Unauthorized = 3       // App未授权蓝牙权限，无法识别系统蓝牙是否开启
    case PoweredOff = 4         // 蓝牙未开启，App已有授权
    case PoweredOn = 5          // 蓝牙已开启，可以访问蓝牙API了

    public var name: String {
        switch self {
        case .Unknown: return "Unknown"
        case .Resetting: return "Resetting"
        case .Unsupported: return "Unsupported"
        case .Unauthorized: return "Unauthorized"
        case .PoweredOff: return "PoweredOff"
        case .PoweredOn: return "PoweredOn"

        default: return "Unknown"
        }
    }

    public var description: String {
        return "BLESysState:(\(rawValue)) ." + name
    }
}

@objc(XPAutoLockResult)
public enum AutoLockResult : Int, CustomStringConvertible {

    case success = 0
    case fail = 1

    public var name: String {
        switch self {
        case .success: return "success"
        case .fail: return "fail"
        }
    }

    public var description: String {
        return "AutoLockResult:(\(rawValue)) ." + name
    }
}

