#import "XPSDK2ndKeyManager.h"
#import "DNotification.h"
@import XPVehicleSDK;

@implementation XPSDK2ndKeyManager

+ (instancetype)instance {
    static XPSDK2ndKeyManager* __instance = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        __instance = [[XPSDK2ndKeyManager alloc] init];
    });

    return __instance;
}

- (instancetype)init
{
    self = [super init];
    if (self) {
        [[[NSNotificationCenter defaultCenter] rac_addObserverForName:XPVehicleNotification.DigitalKeyStateChanged object:nil]  subscribeNext:^(NSNotification * _Nullable notification) {
            [[NSNotificationCenter defaultCenter] postNotificationName:BLEKeyButtonUpdateNotification object:nil];
        }];
    }
    return self;
}

@end

