- (void)deleteMessageWithCardNo:(NSString *)cardNo vin:(NSString *)vin {
    if (StringIsEmpty(cardNo) || StringIsEmpty(vin)) {
        return;
    }
    XPBLEKeyCard *safeCard = XPBLEKeyManager.instance.defaultCard;

    if (safeCard && [safeCard isValidInOldCode] && [safeCard.cardNo isEqualToString:cardNo]) {
        NSInteger count = [self getSafeMessageCountWithVin:vin cardNo:cardNo];
        if (count > 0) {
            EtasConfiguration* config = [XPBLEKeyManager createEtasConfiguration:vin cardNo:cardNo];
            EtasGetAuthDataSession* session = [EtasGetAuthDataSession createSessionWithConfig:config];
            [session clearIfaaAuthData];
        }
    } else {
        [CertKeyMessage removeMessageWithVin:vin uid:CTMediator.uid cardNo:cardNo];
    }
}

- (NSString *)getOneCertMessageWithVin:(NSString *)vin cardNo:(NSString *)cardNo {
    for (XPBLEKeyCard *card in self.allCardList) {
        if ([cardNo isEqualToString:card.cardNo]) {
            return [CertKeyMessage getOneMessageWithVin:vin cardNo:cardNo].message;
        }
    }
    return nil;
}

- (void)getOneSafeMessageWithVin:(NSString *)vin cardNo:(NSString *)cardNo callback:(void (^)(NSString * _Nullable message))callback{
    if (StringIsEmpty(vin)) {
        callback(nil);
        return;
    }
    XPBLEKeyCard *card = [self safeKeyCard];
    if (card && [card isValidInOldCode] && [card.cardNo isEqualToString:cardNo]) {
        [[[XPBLEKeyManager.instance.verifyCommand execute:nil] takeUntil:self.rac_willDeallocSignal].deliverOnMainThread subscribeNext:^(NSString*  _Nullable ifaaMsg) {
            callback(ifaaMsg);
        } error:^(NSError * _Nullable error) {
            callback(nil);
        }];
    } else {
        callback(nil);
    }
}

