    @objc optional func readDigitalKeyList() -> [String: Any]?
    @objc optional func refreshDigitalKeyList(dataList: [String: Any]?, uid: UInt64, vin: String?)
    @objc optional func getOneCertMessage(vin: String?, cardNo:String?) -> String?
    @objc optional func getOneSafeMessage(vin: String?, cardNo: String?, callback: @escaping (_ message: String?) -> Void)
    @objc optional func getSafeMessageCount(vin: String?, cardNo: String?) -> Int
    @objc optional func checkKeyExist(cardNo: String) -> Bool
    @objc optional func markMonaCreateStep(mark :Bool)
    // 读取 App 当前车辆
    @objc optional func readSelectedVehicleVin() -> String?

    // writeAppMqttAccount
    @objc optional func writeAppMqttAccount(mqttAccount: [String: Any]? )

}

