            XPBleParkInfo *bleParkInfo = data;
            //信号处理
            self.parkingState = (XPAppAutoParkingState)bleParkInfo.parkState;
            [self onParkingStateUpdate:self.parkingState];
            self.eventTrack.parkingState = self.parkingState;

            self.parkingExpState = (XPAppAutoParkingExpType)bleParkInfo.failCode;
            [self onParkingExpUpdate:self.parkingExpState];
            self.eventTrack.parkingExpState = self.parkingExpState;

            self.parkingAnimation = (XPAppAutoParkingAnimation)bleParkInfo.animation;

            if (bleParkInfo.animation != -1 && self.parkingAnimation != XPAutoParkingAnimationInvalid) {
                self.lastValidAnim = self.parkingAnimation;
            }

            [self handleParkingAnimate:self.parkingAnimation];

