@implementation XPKeyCheckViewController

+ (BOOL)resumeFromRestart{
    return [MMKV.defaultMMKV getBoolForKey:kResumeKeyCheckFromRestart defaultValue:NO];
}

+ (void)markResumeFromRestart:(BOOL)resume{
    [MMKV.defaultMMKV setBool:resume forKey:kResumeKeyCheckFromRestart];
}

+ (uint8_t)resumeCommand{
    return [MMKV.defaultMMKV getUInt32ForKey:kResumeCommandKeyCheckFromRestart];
}

+ (void)markResumeCommand:(uint8_t)cmd{
    [MMKV.defaultMMKV setUInt32:cmd forKey:kResumeCommandKeyCheckFromRestart];
}

+ (BOOL)resumeSkipAlert{
    return [MMKV.defaultMMKV getBoolForKey:kResumeSkipAlertKeyCheckFromRestart defaultValue:NO];
}

+ (void)markSkipAlert:(BOOL)skipAlert{
    [MMKV.defaultMMKV setBool:skipAlert forKey:kResumeSkipAlertKeyCheckFromRestart];
}

+ (uint64_t)resumeSessionId{
    return [MMKV.defaultMMKV getUInt64ForKey:kResumeSessionIdKeyCheckFromRestart];
}

+ (void)markResumeSessionId:(uint64_t)sessionId{
    [MMKV.defaultMMKV setUInt64:sessionId forKey:kResumeSessionIdKeyCheckFromRestart];
}

- (void)dealloc{
    DLogTagInfo(kBLEKeyTag, @"dealloc");
}

- (instancetype)init{
    self = [super init];
    if (self) {
        _sessionId = (uint64_t)([[NSDate date] timeIntervalSince1970] * 1000);
        _viewDidAppearSubject = [RACSubject subject];
        _bleConnectStateSubject = [RACSubject subject];
        _sysBleStateSubject = [RACReplaySubject replaySubjectWithCapacity:1];
    }
    return self;
}

- (void)setupNav {
    self.fd_prefersNavigationBarHidden = YES;

    XPCommonNavigationBar *textBar = [[XPCommonNavigationBar alloc] initWithFrame:CGRectMake(0, 0, SCREEN_WIDTH, kTopBarHeight)];
    textBar.layer.zPosition = 999;
    [textBar setTitle:@"钥匙检查与启动"];
    textBar.titleLabel.font = [UIFont xp_titleRegularFont];
    textBar.backgroundColor = UIColorClear;
    [self.view addSubview:textBar];
}

- (void)loadView{
