- (XPTBoxCommand)command{
    XPTBoxCommand result = [self.params[@"command"] unsignedShortValue];
    if(result == 0) result = XPTBoxCommandUnlock;
    return result;
}

- (uint64_t)sessionId{
    uint64_t sessionId = [self.params[@"sessionId"] unsignedLongLongValue];
    if(sessionId != 0) return sessionId;
    return _sessionId;
}

- (NSInteger)from{
    NSInteger from = [self.params[@"from"] integerValue];
    if(from == 0) return 4;
    return from;
}

- (BOOL)skipAlert{
    BOOL skipAlert = [self.params[@"skipAlert"] boolValue];
    return skipAlert;
}

- (BOOL)isStart{
    return self.carInfo.isE28 || self.carInfo.isD22;
}

- (BOOL)remoteStartIsSupported{
    return self.carInfo.isSupportRemoteStart;
}

