#define kResumeSessionIdKeyCheckFromRestart @"com.xiaopeng.XPKeyCheck.Resume.SessionId"

NSString *const XPKeyCheckErrorDomain = @"com.xiaopeng.XPKeyCheck.Error";

#define kKeyCheckTag @"钥匙检查"

typedef NS_ENUM(NSInteger, XPKeyCheckErrorCode) {
    XPKeyCheckErrorCodeDefault = 0,
    XPKeyCheckErrorCodeNoKey,
    XPKeyCheckErrorCodeFailToCreateKey,
    XPKeyCheckErrorCodePoweredOff,
    XPKeyCheckErrorCodeNoPermission,
    XPKeyCheckErrorCodeNotNearby,
    XPKeyCheckErrorCodeOccupied,
    XPKeyCheckErrorCodeFailToConnect,
    XPKeyCheckErrorCodeFailToAuth,
    XPKeyCheckErrorCodeFailToSend,
    XPKeyCheckErrorCodeFailToExecute,
    XPKeyCheckErrorCodeFailToResetBle,
    XPKeyCheckErrorCodeExecuteTimeout,
    XPKeyCheckErrorCodeKeyError,
    XPKeyCheckErrorCodeRemoteStarted,
    XPKeyCheckErrorCodeRemoteLocked,
    XPKeyCheckErrorCodeGoToFinal,
    XPKeyCheckErrorCodeCancel,
};

typedef NS_ENUM(NSInteger, XPKeyCheckProgress) {
    XPKeyCheckProgressDefault = 0,
    XPKeyCheckProgressCreateKeyChecking,
    XPKeyCheckProgressCreateKeyChecked,
    XPKeyCheckProgressBleStateChecking,
    XPKeyCheckProgressBleStateChecked,
    XPKeyCheckProgressNearbyChecking,
    XPKeyCheckProgressNearbyChecked,
    XPKeyCheckProgressResetBleChecking,
    XPKeyCheckProgressResetBleChecked,
    XPKeyCheckProgressRestartChecking,
    XPKeyCheckProgressRestartChecked,
    XPKeyCheckProgressConnectChecking,
    XPKeyCheckProgressConnectChecked,
    XPKeyCheckProgressCommandChecking,
    XPKeyCheckProgressCommandChecked,
