- (RACSignal<NSNumber*> *)sendMonaCommandSignalWithTryCount:(NSInteger)tryCount tryDelete:(BOOL)tryDelete{

    @weakify(self);
    return [[RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        [subscriber sendNext:@(XPKeyCheckProgressCommandChecking)];
        RACCompoundDisposable* disposable = [RACCompoundDisposable compoundDisposable];
        [XPVehicleSDK.shared.vehicleManager.currentVehicle sendCommand:XPVehicleCommandBleUnlockStart success:^{
            DLogTagInfo(kBLEKeyTag, @"Mona发送解锁启动成功");
            [subscriber sendNext:@(XPKeyCheckProgressCommandChecked)];
            [subscriber sendCompleted];

        } failed:^(XPVehicleError * error) {
            [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeKeyError userInfo:@{}]];
            DLogTagError(kBLEKeyTag, @"Mona发送解锁启动失败");
        }];

        return disposable;
    }] catch:^RACSignal * _Nonnull(NSError * _Nonnull error) {
        @strongify(self);
        [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_FAIL_COMMAND_FAILED module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];

        return [RACSignal error:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeGoToFinal userInfo:@{}]];
    }];
}
- (RACSignal<NSNumber*> *)sendCommandSignalWithTryCount:(NSInteger)tryCount tryDelete:(BOOL)tryDelete{
    @weakify(self);
    return [[RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        @strongify(self);
        [subscriber sendNext:@(XPKeyCheckProgressCommandChecking)];
        RACSignal *cmdExecuteSignal = nil;
        // 蓝牙发送指令方法改为SDK调用
        if ([CTMediator isSDK2ndCar]) {
            XPVehicleCommand command = XPVehicleCommandBleUnlockStart;
            if (self.command == XPTBoxCommandLock) {
                command = XPVehicleCommandLock;
            }
            cmdExecuteSignal = [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
                if (XPVehicleSDK.currentVehicle == nil) {
                    [subscriber sendError:[NSError errorWithDomain:XPCarControlErrorDomain code:XPCarControlErrorCodeDefault userInfo:@{NSLocalizedFailureReasonErrorKey: @"未设置当前车辆"}]];
                    return nil;
                }
                [XPVehicleSDK.currentVehicle sendCommand:command success:^{
                    [subscriber sendCompleted];
                } failed:^(XPVehicleError * _Nonnull error) {
                    NSInteger code = error.code;
                    if (error.channel == XPVehicleChannelBLE) {
                        if (error.code > 0) {
                            code = XPCarControlErrorCodeBleExecFailed;
                        } else if (error.code == XPVehicleErrorCodeTimeout){
                            code = XPCarControlErrorCodeBleExecTimeout;
                        } else if (error.code == XPVehicleErrorCodeBLEDisconnected || error.code == XPVehicleErrorCodeBLEWriteError) {
                            code = XPCarControlErrorCodeBleSendFailed;
                        }
                    }
                    [subscriber sendError:[NSError errorWithDomain:XPCarControlErrorDomain code:code userInfo:@{}]];
                }];
                return nil;
            }];
        } else {
            cmdExecuteSignal = [XPCarControlViewModel.sharedInstance bleControlSignalWithByte:self.command resultTimeout:5];
        }

        RACDisposable *disposable = [cmdExecuteSignal subscribeNext:^(id  _Nullable x) {

        } error:^(NSError * _Nullable error) {
            @strongify(self);
            if([error.domain isEqualToString:XPCarControlErrorDomain]){
                if(error.code == XPCarControlErrorCodeBleSendFailed){
                    [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeFailToSend userInfo:@{}]];
                }else if(error.code == XPCarControlErrorCodeBleExecFailed){
                    XPTBoxCommand cmd = self.command;
                    NSString *failTitle = @"操作失败";
                    if(cmd == XPTBoxCommandUnlock){
                        failTitle = self.isStart?@"启动失败":@"解锁失败";
                    }else if(cmd == XPTBoxCommandLock){
                        failTitle = @"闭锁失败";
                    }
                    [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeFailToExecute userInfo:@{NSLocalizedFailureReasonErrorKey: error.localizedFailureReason?:@"", @"title": failTitle, @"code": error.userInfo[@"code"]?:@0}]];
                }else if(error.code == XPCarControlErrorCodeBleExecTimeout){
                    [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeExecuteTimeout userInfo:@{}]];
                }else{
                    [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeKeyError userInfo:@{}]];
                }
            }
        } completed:^{
            @strongify(self);
            [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_SUCCESS module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
            if(self.command == XPTBoxCommandUnlock){
                [XPCarControlViewModel.sharedInstance sendLoginUidIfNeeded];
            }
            [subscriber sendNext:@(XPKeyCheckProgressCommandChecked)];
            [subscriber sendCompleted];
        }];

        return disposable;
    }] catch:^RACSignal * _Nonnull(NSError * _Nonnull error) {
        @strongify(self);
        [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_FAIL_COMMAND_FAILED module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];

        if(error.code == XPKeyCheckErrorCodeFailToSend){
            if(tryCount == 0){
                return [RACSignal error:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeGoToFinal userInfo:@{}]];
            }

            if(tryCount == 1){
                return [self restartAppSignal];
            }

            return [[self resetBleSignal] concat:[self sendCommandSignalWithTryCount:tryCount-1]];
        }

        if(error.code == XPKeyCheckErrorCodeFailToExecute){
            XPTBoxCanControlState state = [error.userInfo[@"code"] unsignedIntValue];
            if(state != XPTBoxCanControlStateDuoChannelLockDuplicated && state != XPTBoxCanControlState4GControlIsProcessing && error.localizedFailureReason.length > 0){
                return [RACSignal error:error];
            }
        }

        if(tryDelete){
            return [[self alertControllerSignalWithTitle:@"重建手机钥匙" message:@"将先删除、再创建手机钥匙，可解决大部分手机钥匙问题。请确保网络畅通" buttonTitles:@[@"取消", @"确认"]] flattenMap:^__kindof RACSignal * _Nullable(id  _Nullable value) {
                @strongify(self);
                if([value integerValue] == 0){
                    return [RACSignal error:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeCancel userInfo:@{}]];
                }
                [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_TRY_RECREATE_KEY module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
                return [[self showCreateKeySignalWithNeedDelete:YES] concat:[self sendCommandSignalWithTryCount:tryCount tryDelete:NO]];
            }];
        }

        return [RACSignal error:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeGoToFinal userInfo:@{}]];
    }];
}

