- (RACSignal<NSNumber *> *)alertControllerSignalWithTitle:(NSString *)title message:(NSString *)message buttonTitles:(NSArray<NSString *> *)buttonTitles{
    NSTextAlignment alignment = NSTextAlignmentCenter;
    if([message containsString:@"\n"]){
        alignment = NSTextAlignmentLeft;
    }
    return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        NSString *leftStr = nil;
        NSString *rightStr = nil;
        if (buttonTitles.count > 0) {
            if (buttonTitles.count > 1) {
                leftStr = buttonTitles[0];
                rightStr = buttonTitles[1];
            } else {
                rightStr = buttonTitles[1];
            }
        }
        QMUIAlertController * alert = [QMUIAlertController showAlertWithTitle:title
                                        message:message
                               leftButtionTitle:leftStr
                                 leftButtonType:QMUIAlertActionStyleCancel
                                     leftAction:^(__kindof QMUIAlertController * _Nonnull alertVC, QMUIAlertAction * _Nonnull action) {

            [subscriber sendNext:@(0)];
            [subscriber sendCompleted];
        }
                               rightButtonTitle:rightStr
                                rightButtonType:QMUIAlertActionStyleDefault
                                    rightAction:^(__kindof QMUIAlertController * _Nonnull alertVC, QMUIAlertAction * _Nonnull action) {
            [subscriber sendNext:leftStr.length ? @(1): @(0)];
            [subscriber sendCompleted];
        }];
        return [RACDisposable disposableWithBlock:^{
            dispatch_async(dispatch_get_main_queue(), ^{
                [alert hideWithAnimated:NO];
            });
        }];
    }];
}

- (XPKeyCheckingCellItem *)itemWithType:(XPKeyCheckingCellType)type{
    NSArray *items = [NSArray arrayWithArray:self.items];
    for(XPKeyCheckingCellItem *item in items){
        if(item.type == type){
            return item;
        }
    }
    return nil;
}

- (void)makeItemCheckingWithType:(XPKeyCheckingCellType)type{
    XPKeyCheckingCellItem *item = [self itemWithType:type];
    if(!item){
        item = [XPKeyCheckingCellItem new];
        item.type = type;
        item.state = XPKeyCheckingStateChecking;
        [self.items addObject:item];
    }else{
        [self.items removeObject:item];
        [self.items addObject:item];
        item.state = XPKeyCheckingStateChecking;
    }
    if(self.items.count > 5) [self.items removeObjectAtIndex:0];
}

- (void)makeItemSuccessWithType:(XPKeyCheckingCellType)type{
    XPKeyCheckingCellItem *item = [self itemWithType:type];
    item.state = XPKeyCheckingStateSuccess;
}

