- (void)addBleConnectStateObserver {
    @weakify(self);
    [[[[[NSNotificationCenter defaultCenter] rac_addObserverForName:XPVehicleNotification.BLEConnectStateChanged object:nil] takeUntil:self.rac_willDeallocSignal] deliverOnMainThread] subscribeNext:^(NSNotification * _Nullable x) {
        @strongify(self);
        XPBLEConnectionNotiObject *not = x.userInfo[@"state"];
        if (![not isKindOfClass:[XPBLEConnectionNotiObject class]]) {
            return;
        }
        NSDictionary *dict = @{
            XP_BLEKEY_CONNECT_STATE_KEY: @(not.connectState),
        };
        [self.bleConnectStateSubject sendNext:dict];
    }];

    [self.sysBleStateSubject sendNext:@(XPVehicleSDK.shared.vehicleManager.bleSysState)];
    [[[[[NSNotificationCenter defaultCenter] rac_addObserverForName:XPVehicleNotification.BLESysStateChanged object:nil] takeUntil:self.rac_willDeallocSignal] deliverOnMainThread] subscribeNext:^(NSNotification * _Nullable x) {
        @strongify(self);
        XPBLESysStateNotiObject *not = x.userInfo[@"state"];
        if (![not isKindOfClass:[XPBLESysStateNotiObject class]]) {
            return;
        }
        [self.sysBleStateSubject sendNext:@(not.bleSysState)];
    }];
}

