}

- (RACSignal<NSNumber *> *)showCreateKeySignalWithNeedDelete:(BOOL)needDelete{
    if(!NetworkMonitorManager.sharedManager.isReachable){
        return [RACSignal error:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeFailToCreateKey userInfo:@{NSLocalizedFailureReasonErrorKey: @"创建手机钥匙失败，请检查手机和车辆网络"}]];
    }

    @weakify(self);
    RACSignal *deleteSignal = RACSignal.empty;
    if(needDelete){
        deleteSignal = [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
            @strongify(self);
            RACDisposable *disposable = [[[self.viewDidAppearSubject take:1] delay:3].deliverOnMainThread subscribeCompleted:^{
                @strongify(self);
                if(![self existValidBlePrivateKey]){
                    [subscriber sendCompleted];
                }else{
                    [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeFailToCreateKey userInfo:@{NSLocalizedFailureReasonErrorKey: @"删除手机钥匙失败，请检查手机和车辆网络"}]];
                }
            }];

            XPBLEKeyCard *safeKeyCard = nil;
            if(self.carInfo.isE28){
                XPDigitalKey *key = [XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager digitalKeyWithKeyCardType:XPKeyCardTypeSAFE];
                XPSDKBLEKeyCard *card = key.bleKeyCard;
                NSDictionary *dict = [card toDict];
                XPBLEKeyCard *bleKeyCard = [XPBLEKeyCard yy_modelWithDictionary:dict];
                safeKeyCard = bleKeyCard;
            }

            dispatch_async(dispatch_get_main_queue(), ^{
                if(safeKeyCard){
                    JRDeleteKeyViewController *vc = [[JRDeleteKeyViewController alloc] init];
                    vc.vin = self.carInfo.vin;
                    vc.card = safeKeyCard;
                    [self safePushViewController:vc animated:YES];
                }else{
                    JRDeleteCertKeyViewController *vc = [[JRDeleteCertKeyViewController alloc] init];
                    vc.vin = self.carInfo.vin;
                    [self safePushViewController:vc animated:YES];
                }
            });

            return disposable;
        }];
    }

    RACSignal *createSignal = [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        @strongify(self);
        RACDisposable *disposable = [[[self.viewDidAppearSubject take:1] delay:3].deliverOnMainThread subscribeCompleted:^{
            @strongify(self);
            if([self existValidBlePrivateKey]){
                [subscriber sendCompleted];
            }else{
                [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeFailToCreateKey userInfo:@{NSLocalizedFailureReasonErrorKey: @"创建手机钥匙失败，请检查手机和车辆网络"}]];
            }
        }];

        dispatch_async(dispatch_get_main_queue(), ^{
            XPCreateDigitalKeyViewModel *createViewModel = [[XPCreateDigitalKeyViewModel alloc] init];
            [createViewModel createKeyWithViewController:self andCarInfo:self.carInfo preventPopToRootViewController:YES];
        });

        return disposable;
    }];

    RACSignal *prefixSignal = @[@(XPKeyCheckProgressDefault), @(XPKeyCheckProgressCreateKeyChecking)].rac_sequence.signal;
    RACSignal *suffixSignal = [RACSignal return:@(XPKeyCheckProgressCreateKeyChecked)];
    if(needDelete){
        prefixSignal = [RACSignal return:@(XPKeyCheckProgressResetKeyChecking)];
        suffixSignal = [RACSignal return:@(XPKeyCheckProgressResetKeyChecked)];
    }

    return [[prefixSignal concat:[deleteSignal concat:createSignal]] concat:suffixSignal];
}

- (RACSignal<NSNumber *> *)createKeySignalWithNeedDelete:(BOOL)needDelete{
    if(!NetworkMonitorManager.sharedManager.isReachable){
        return [RACSignal error:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeFailToCreateKey userInfo:@{NSLocalizedFailureReasonErrorKey: @"创建手机钥匙失败，请检查手机和车辆网络"}]];
    }

    RACSignal *createSignal = nil;
    if(self.carInfo.isE28){
        XPCreateEtasKeyViewController *vc = [[XPCreateEtasKeyViewController alloc] init];
        vc.carInfo = self.carInfo;
        if(!self.carInfo.isMyOwnerCar){
            vc.shareFromUid = self.carInfo.ownerInfo.uid;
        }
        createSignal = [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
            RACCompoundDisposable *disposable = [RACCompoundDisposable compoundDisposable];

            __block NSError *etasError = nil;
            __block BOOL etasComplete = NO;
            __block NSError *certError = nil;
            __block BOOL certComplete = NO;
            [disposable addDisposable:[[vc.createEtasKeyCommand execute:@{}].deliverOnMainThread subscribeNext:^(id  _Nullable x) {

            } error:^(NSError * _Nullable error) {
                etasError = error;
                if(certError){
                    [subscriber sendError:error];
                }else if(certComplete){
                    [subscriber sendCompleted];
                }
            } completed:^{
                etasComplete = YES;
                if(certError || certComplete){
                    [subscriber sendCompleted];
                }
            }]];

            [disposable addDisposable:[[vc.createCertKeyCommand execute:@{@"needDelete": @(needDelete)}].deliverOnMainThread subscribeNext:^(id  _Nullable x) {

            } error:^(NSError * _Nullable error) {
                certError = error;
                if(etasError){
                    [subscriber sendError:etasError];
                }else if(etasComplete){
                    [subscriber sendCompleted];
                }
            } completed:^{
                certComplete = YES;
                if(etasError || etasComplete){
                    [subscriber sendCompleted];
                }
            }]];

            return disposable;
        }];
        self.createKeyViewController = vc;
    }else{
        XPCreateSelfKeyViewController *vc = [[XPCreateSelfKeyViewController alloc] init];
        vc.carInfo = self.carInfo;
        createSignal = [vc.createSelfKeyCommand execute:@{@"needDelete": @(needDelete)}];
        self.createKeyViewController = vc;
    }

    RACSignal *prefixSignal = @[@(XPKeyCheckProgressDefault), @(XPKeyCheckProgressCreateKeyChecking)].rac_sequence.signal;
    RACSignal *suffixSignal = [RACSignal return:@(XPKeyCheckProgressCreateKeyChecked)];
    if(needDelete){
        prefixSignal = [RACSignal return:@(XPKeyCheckProgressResetKeyChecking)];
        suffixSignal = [RACSignal return:@(XPKeyCheckProgressResetKeyChecked)];
    }

    @weakify(self);
    createSignal = [createSignal doCompleted:^{
        @strongify(self);
        // SDK 2.0 车型无需手动刷新钥匙列表
        [[NSNotificationCenter defaultCenter] postNotificationName:BLEKeyButtonUpdateNotification object:nil];
    }];

    return [[[prefixSignal concat:[createSignal.ignoreValues delay:5]] concat:suffixSignal] catch:^RACSignal * _Nonnull(NSError * _Nonnull error) {
        DLogTagError(kBLEKeyTag, @"create key failed with error %@", error);
        return [RACSignal error:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeFailToCreateKey userInfo:@{NSLocalizedFailureReasonErrorKey: @"创建手机钥匙失败，请检查手机和车辆网络"}]];
    }];
}

- (RACSignal<NSNumber *> *)checkRemoteSignalWithSkipAlert:(BOOL)skipAlert{
    if(self.command == XPTBoxCommandLock) return [self checkRemoteLockSignalWithSkipAlert:skipAlert];
    if(self.command == XPTBoxCommandUnlock) return [self checkRemoteStartSignalWithSkipAlert:skipAlert];
    return RACSignal.empty;
}

- (RACSignal<NSNumber *> *)checkRemoteLockSignalWithSkipAlert:(BOOL)skipAlert{
    if(self.command != XPTBoxCommandLock){
        return RACSignal.empty;
    }

    if(!NetworkMonitorManager.sharedManager.isReachable){
        return RACSignal.empty;
    }

    if(XPCarStateViewModel.sharedInstance.remoteConnectState != XPCarConnectStateConnected){
        return RACSignal.empty;
    }

    @weakify(self);
    RACSignal *lockSignal = [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        RACDisposable *disposable = [[XPCarControlViewModel.sharedInstance.lockDoorCommand execute:@{@"tryBle": @NO}] subscribeNext:^(id  _Nullable x) {

        } error:^(NSError * _Nullable error) {
            [XPToast showMessage:@"远程闭锁失败"];
            [subscriber sendCompleted];
        } completed:^{
            @strongify(self);
            [XPStatisticsMgr sendEvent:skipAlert? XP_MOBILE_KEY_CHECK_REMOTE_SUCCESS_WITHOUT_ALERT: XP_MOBILE_KEY_CHECK_REMOTE_SUCCESS_WITH_ALERT module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
            [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeRemoteLocked userInfo:@{}]];
        }];
        return disposable;
    }];

    if(skipAlert){
        return lockSignal;
    }

    return [[self alertControllerSignalWithTitle:@"是否闭锁车辆" message:@"当前网络通畅，请确认闭锁车辆" buttonTitles:@[@"取消", @"确认"]] flattenMap:^__kindof RACSignal * _Nullable(id  _Nullable value) {
        if([value integerValue] == 0){
            return RACSignal.empty;
        }
        return lockSignal;
    }];
}

- (RACSignal<NSNumber *> *)checkRemoteStartSignalWithSkipAlert:(BOOL)skipAlert{
    if(![self remoteStartIsSupported]){
        return RACSignal.empty;
    }

    if(self.command != XPTBoxCommandUnlock){
        return RACSignal.empty;
    }

    if(!NetworkMonitorManager.sharedManager.isReachable){
        return RACSignal.empty;
    }

    if(XPCarStateViewModel.sharedInstance.remoteConnectState != XPCarConnectStateConnected){
        return RACSignal.empty;
    }

    @weakify(self);
    RACSignal *startSignal = [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        RACDisposable *disposable = [[XPCarControlViewModel.sharedInstance.controlRemoteStartCommand execute:@{}] subscribeNext:^(id  _Nullable x) {

        } error:^(NSError * _Nullable error) {
            [XPToast showMessage:@"远程启动失败"];
            [subscriber sendCompleted];
        } completed:^{
            @strongify(self);
            [XPStatisticsMgr sendEvent:skipAlert? XP_MOBILE_KEY_CHECK_REMOTE_SUCCESS_WITHOUT_ALERT: XP_MOBILE_KEY_CHECK_REMOTE_SUCCESS_WITH_ALERT module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
            [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeRemoteStarted userInfo:@{}]];
        }];
        return disposable;
    }];

    if(skipAlert){
        return startSignal;
    }

    return [[self alertControllerSignalWithTitle:@"是否解锁并启动车辆" message:@"当前网络通畅，请确认解锁并启动车辆" buttonTitles:@[@"取消", @"确认"]] flattenMap:^__kindof RACSignal * _Nullable(id  _Nullable value) {
        if([value integerValue] == 0){
            return RACSignal.empty;
        }
        return startSignal;
    }];
}

- (RACSignal<NSNumber *> *)checkBleStateSignalWithTimeout:(NSTimeInterval)timeout{
    @weakify(self);
    return [[RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        [subscriber sendNext:@(XPKeyCheckProgressBleStateChecking)];

        RACCompoundDisposable *disposable = [RACCompoundDisposable compoundDisposable];

        @strongify(self);
        NSError *error = [NSError errorWithDomain:XPKeyCheckErrorDomain code:5 userInfo:@{NSLocalizedFailureReasonErrorKey: @"蓝牙未开启"}];
        RACSignal *sysBleStateSingal = [[[self.sysBleStateSubject filter:^BOOL(id  _Nullable value) {
            return [value integerValue] == XPBLESysStatePoweredOn;
        }] take:1] timeout:timeout onScheduler:RACScheduler.scheduler error:error];

        [disposable addDisposable: [sysBleStateSingal subscribeNext:^(id  _Nullable x) {} error:^(NSError * _Nullable error) {
            @strongify(self);
            if([self isUnauthorized]){
                [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeNoPermission userInfo:@{NSLocalizedFailureReasonErrorKey: @"手机蓝牙权限开启失败，请开启权限", NSLocalizedRecoverySuggestionErrorKey: @"手机钥匙需访问蓝牙扫描和连接权限，用于识别与连接您的车辆", NSLocalizedDescriptionKey: @"请开启蓝牙权限"}]];
            }else{
                [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodePoweredOff userInfo:@{NSLocalizedFailureReasonErrorKey: @"手机蓝牙开启失败，请开启蓝牙", NSLocalizedRecoverySuggestionErrorKey: @"使用蓝牙钥匙需打开手机蓝牙开关", NSLocalizedDescriptionKey: @"请开启蓝牙开关"}]];
            }
        } completed:^{
            [subscriber sendNext:@(XPKeyCheckProgressBleStateChecked)];
            [subscriber sendCompleted];
        }]];

        return disposable;
    }] catch:^RACSignal * _Nonnull(NSError * _Nonnull error) {
        @strongify(self);
        if(error.code == XPKeyCheckErrorCodeNoPermission){
            [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_FAIL_BLE_PERMISSION module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
        }else{
            [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_FAIL_BLE_POWERED_OFF module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
        }

        return [[[self alertControllerSignalWithTitle:error.localizedDescription message:error.localizedRecoverySuggestion buttonTitles:@[@"取消", @"立即开启"]] flattenMap:^__kindof RACSignal * _Nullable(id  _Nullable value) {
            @strongify(self);
            if([self isPoweredOn]){
                return RACSignal.empty;
            }
            if([value integerValue] == 1){
                if(error.code == XPKeyCheckErrorCodeNoPermission){
                    [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_TRY_BLE_PERMISSION module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
                }else{
                    [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_TRY_BLE_POWER_ON module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
                }

                if(error.code == XPKeyCheckErrorCodePoweredOff){
                    return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
                        @strongify(self);
                        XPBleGuideViewController *vc = [XPBleGuideViewController new];
                        vc.confirmBlock = ^{
                            if([self isPoweredOn]){
                                [subscriber sendCompleted];
                            }else if([self isUnauthorized]){
                                [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeNoPermission userInfo:@{NSLocalizedFailureReasonErrorKey: @"手机蓝牙权限开启失败，请开启权限", NSLocalizedRecoverySuggestionErrorKey: @"手机钥匙需访问蓝牙扫描和连接权限，用于识别与连接您的车辆", NSLocalizedDescriptionKey: @"请开启蓝牙权限"}]];
                            }else{
                                [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodePoweredOff userInfo:@{NSLocalizedFailureReasonErrorKey: @"手机蓝牙开启失败，请开启蓝牙", NSLocalizedRecoverySuggestionErrorKey: @"使用蓝牙钥匙需打开手机蓝牙开关", NSLocalizedDescriptionKey: @"请开启蓝牙开关"}]];
                            }
                        };
                        vc.closeBlock = ^{
                            @strongify(self);
                            if([self isPoweredOn]){
                                [subscriber sendCompleted];
                            }else if([self isUnauthorized]){
                                [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeNoPermission userInfo:@{NSLocalizedFailureReasonErrorKey: @"手机蓝牙权限开启失败，请开启权限", NSLocalizedRecoverySuggestionErrorKey: @"手机钥匙需访问蓝牙扫描和连接权限，用于识别与连接您的车辆", NSLocalizedDescriptionKey: @"请开启蓝牙权限"}]];
                            }else{
                                [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodePoweredOff userInfo:@{NSLocalizedFailureReasonErrorKey: @"手机蓝牙开启失败，请开启蓝牙", NSLocalizedRecoverySuggestionErrorKey: @"使用蓝牙钥匙需打开手机蓝牙开关", NSLocalizedDescriptionKey: @"请开启蓝牙开关"}]];
                            }
                        };
                        [vc showInViewController:self];
                        return [RACDisposable disposableWithBlock:^{
                            dispatch_async(dispatch_get_main_queue(), ^{
                                [vc dismiss];
                            });
                        }];
                    }];
                }else{
                    NSURL *url = [NSURL URLWithString:UIApplicationOpenSettingsURLString];
                    if([UIApplication.sharedApplication canOpenURL:url]) [UIApplication.sharedApplication openURL:url options:@{} completionHandler:^(BOOL success) {}];
                    return [[RACSignal.empty delay:0.5] concat:[RACSignal error:error]];
                }
            }

            return [RACSignal error:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeCancel userInfo:@{}]];
        }] then:^RACSignal * _Nonnull{
            @strongify(self);
            return [self checkBleStateSignalWithTimeout:2];
        }];
    }];
}

- (RACSignal<NSNumber *> *)checkNearbySignal{
    return [self checkNearbySignalWithTryCount:2];
}

- (RACSignal<NSNumber *> *)checkNearbySignalWithTryCount:(NSInteger)tryCount{
    // Debug
//    return @[@(XPKeyCheckProgressNearbyChecking), @(XPKeyCheckProgressNearbyChecked)].rac_sequence.signal;

    if(XPCarStateViewModel.sharedInstance.bleConnectState == XPCarConnectStateConnected){
        return @[@(XPKeyCheckProgressNearbyChecking), @(XPKeyCheckProgressNearbyChecked)].rac_sequence.signal;
    }

    @weakify(self);
    return [[RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        @strongify(self);
        [subscriber sendNext:@(XPKeyCheckProgressNearbyChecking)];

        RACCompoundDisposable *disposable = [RACCompoundDisposable compoundDisposable];

        RACSignal *currentBleStateSignal = [RACSignal return:@{
            XP_BLEKEY_IS_COMMUNICATE_KEY: @(true),
            XP_BLEKEY_CONNECT_STATE_KEY: @([XPVehicleSDK bleConnectState])
        }];
        [disposable addDisposable:[[self.bleConnectStateSubject merge:currentBleStateSignal]
                                   subscribeNext:^(NSDictionary * _Nullable x){
            BOOL isCommunicate = [x[XP_BLEKEY_IS_COMMUNICATE_KEY] boolValue];
            XPBLEConnectionState state = [x[XP_BLEKEY_CONNECT_STATE_KEY] intValue];
            if (isCommunicate && state == XPBLEConnectionStateAvailable) {
                [subscriber sendNext:@(XPKeyCheckProgressNearbyChecked)];
                [subscriber sendCompleted];
            }
        }]];

        if(tryCount == 0){
            [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_TRY_RESET_CAR_BLE module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
            [XPCarControlViewModel.sharedInstance.resetBleCommand execute:@{}];
        }

        __block BOOL isConnectable = NO;
        RACSignal *tmpScanSingal = [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
            RACCompoundDisposable *disposable = [RACCompoundDisposable compoundDisposable];
            [disposable addDisposable:[self.sysBleStateSubject subscribeNext:^(id  _Nullable x) {
                XPBLESysState state = [x integerValue];
                if (state != XPBLESysStatePoweredOn) {
                    [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPCreateKeyErrorCodeBleNotPowerOn  userInfo:@{}]];
                }
            }]];
            if (XPVehicleSDK.currentVehicle == nil) {
                [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeNotNearby userInfo:@{NSLocalizedFailureReasonErrorKey: @"未设置当前车辆"}]];
                return disposable;
            }
            [self cleanBleInfoCache];
            [self.bleCheckManager scanBleAdvertiseWithTimeout:15 success: ^{
                isConnectable = YES;
                [subscriber sendNext:nil];
                [subscriber sendCompleted];
            } failed:^(XPVehicleError * _Nonnull error) {
                if (error.code == 1) {
                    DLogTagInfo(kBLEKeyTag, @"车辆附近检查-检测到车辆，但已被其它设备连接");
                    isConnectable = NO;
                    [subscriber sendNext:nil];
                    [subscriber sendCompleted];
                    return;
                }
                DLogTagInfo(kBLEKeyTag, @"车辆附近检查-未检测到车辆");
                [subscriber sendError:error.toNSError];
            }];
            return disposable;
        }];

        [disposable addDisposable:[tmpScanSingal subscribeNext:^(CBPeripheral * _Nullable x) {
            if(!isConnectable){
                if (XPVehicleSDK.currentAbilityConfig.bleKeyVersion == BleKeyProtocolVesionV3 || CTMediator.isMona ) {
                    [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeOccupied userInfo:@{NSLocalizedDescriptionKey: @"未检测到附近小鹏汽车，请靠近车辆后重试。如在车辆附近，请点击下一步", NSLocalizedRecoverySuggestionErrorKey: @"", NSLocalizedFailureReasonErrorKey: @"请断开周围其他已授权手机/手表钥匙蓝牙后重试", @"title": @"启动失败，车辆已连接其他设备"}]];
                }else{
                    [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeOccupied userInfo:@{NSLocalizedDescriptionKey: @"未检测到附近小鹏汽车，请确认", NSLocalizedRecoverySuggestionErrorKey: @"1、手机靠近车辆\n2、无其他手机/手表钥匙连接车辆，如有请断开其蓝牙，并重新检查", NSLocalizedFailureReasonErrorKey: @"请断开周围其他已授权手机/手表钥匙蓝牙后重试", @"title": @"启动失败，车辆已连接其他设备"}]];
                }

            }else{
                [subscriber sendNext:@(XPKeyCheckProgressNearbyChecked)];
                [subscriber sendCompleted];
            }
        } error:^(NSError * _Nullable error) {
            if (XPVehicleSDK.currentAbilityConfig.bleKeyVersion == BleKeyProtocolVesionV3 || CTMediator.isMona) {
                [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeNotNearby userInfo:@{NSLocalizedDescriptionKey: @"未检测到附近小鹏汽车，请靠近车辆后重试。如在车辆附近，请点击下一步", NSLocalizedRecoverySuggestionErrorKey: @"", NSLocalizedFailureReasonErrorKey: @"请断开周围其他已授权手机/手表钥匙蓝牙后重试"}]];
            }else{
                [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeNotNearby userInfo:@{NSLocalizedDescriptionKey: @"未检测到附近小鹏汽车，请确认", NSLocalizedRecoverySuggestionErrorKey: @"1、手机靠近车辆\n2、无其他手机/手表钥匙连接车辆，如有请断开其蓝牙，并重新检查", NSLocalizedFailureReasonErrorKey: @"请断开周围其他已授权手机/手表钥匙蓝牙后重试"}]];
            }

        } completed:^{

        }]];

        return disposable;
    }] catch:^RACSignal * _Nonnull(NSError * _Nonnull error) {
        @strongify(self);
        if(error.code == XPKeyCheckErrorCodeOccupied){
            [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_FAIL_OCCUPIED module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
            return [RACSignal error:error];
        }

        if(tryCount == 0){
            return [RACSignal error:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeGoToFinal userInfo:@{}]];
        }

        if(tryCount == 1){
            return [self restartAppSignal];
        }

        [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_FAIL_NOT_NEARBY module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
        return [[self alertControllerSignalWithTitle:error.localizedDescription message:error.localizedRecoverySuggestion buttonTitles:@[@"重新检查", @"确认，下一步"]] flattenMap:^__kindof RACSignal * _Nullable(id  _Nullable value) {
            @strongify(self);
            if([value integerValue] == 1){
                return [[self resetBleSignal] concat:[self checkNearbySignalWithTryCount:tryCount-1]];
            }
            return [self checkNearbySignal];
        }];
    }];
}

- (RACSignal<NSNumber*> *)resetBleSignal{
    @weakify(self);
    return [[RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        @strongify(self);
        RACCompoundDisposable *disposable = [RACCompoundDisposable compoundDisposable];

        __block BOOL isReset = NO;
        [disposable addDisposable:[[[self.sysBleStateSubject filter:^BOOL(id  _Nullable value) {
            return [value integerValue] != XPBLESysStatePoweredOn;
        }] take: 1].deliverOnMainThread subscribeCompleted:^{
            isReset = YES;
        }]];

        [disposable addDisposable:[[[self alertControllerSignalWithTitle:@"即将重启手机蓝牙" message:@"能解决92%的问题，请先关闭蓝牙，再打开" buttonTitles:@[@"取消", @"确定"]] flattenMap:^__kindof RACSignal * _Nullable(NSNumber * _Nullable value) {
            @strongify(self);
            if([value integerValue] == 0){
                return [RACSignal error:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeCancel userInfo:@{}]];
            }
            [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_TRY_RESET_BLE module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
            if(isReset && [self isPoweredOn]){
                return RACSignal.empty;
            }
            return [[[RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
                @strongify(self);
                XPBleGuideViewController *vc = [XPBleGuideViewController new];
                vc.titleString = @"请重启手机蓝牙";
                vc.confirmBlock = ^{
                    [subscriber sendCompleted];
                };
                vc.closeBlock = ^{
                    [subscriber sendCompleted];
                };
                [vc showInViewController:self];
                return [RACDisposable disposableWithBlock:^{
                    dispatch_async(dispatch_get_main_queue(), ^{
                        [vc dismiss];
                    });
                }];
            }] delay:2].deliverOnMainThread then:^RACSignal * _Nonnull{
                @strongify(self);
                if(isReset && [self isPoweredOn]){
                    return RACSignal.empty;
                }
                return [RACSignal error:nil];
            }];
        }] subscribeNext:^(id  _Nullable x) {

        } error:^(NSError * _Nullable error) {
            [subscriber sendError:error];
        } completed:^{
            [subscriber sendNext:@(XPKeyCheckProgressResetBleChecking)];
            [subscriber sendNext:@(XPKeyCheckProgressResetBleChecked)];
            [subscriber sendCompleted];
        }]];

        return disposable;
    }] catch:^RACSignal * _Nonnull(NSError * _Nonnull error) {
        @strongify(self);
        if(error){
            return [RACSignal error:error];
        }
        return [self resetBleSignal];
    }];
}

- (RACSignal<NSNumber *> *)restartAppSignal{
    @weakify(self);
    return [[self alertControllerSignalWithTitle:@"即将重启App" message:@"重启App能解决大部分未知问题，请点击确认重启后，在桌面重新打开App" buttonTitles:@[@"取消", @"确认重启"]] flattenMap:^__kindof RACSignal * _Nullable(id  _Nullable value) {
        @strongify(self);
        if([value integerValue] == 0){
            return [RACSignal error:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeCancel userInfo:@{}]];
        }
        [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_TRY_RESET_BLE_CACHE module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];

        [self cleanBleInfoCache];

        [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_TRY_RESTART_APP module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
        [self.class markResumeFromRestart:YES];
        [self.class markResumeCommand:self.command];
        [self.class markSkipAlert:self.skipAlert];
        [self.class markResumeSessionId:self.sessionId];
        [NSNotificationCenter.defaultCenter postNotificationName:UIApplicationWillTerminateNotification object:nil];
        exit(0);
        return RACSignal.empty;
    }];
}

- (RACSignal<NSNumber*> *)checkConnectSignal{
    return [self checkConnectSignalWithTryCount:2];
}

- (RACSignal<NSNumber*> *)checkConnectSignalWithTryCount:(NSInteger)tryCount{
    return [self checkConnectSignalWithTryCount:tryCount tryDelete:YES];
}

- (RACSignal<NSNumber*> *)monaCheckConnectSignalWithTryCount:(NSInteger)tryCount{
    @weakify(self);
    return [[RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        [subscriber sendNext:@(XPKeyCheckProgressConnectChecking)];

        RACCompoundDisposable *disposable = [RACCompoundDisposable compoundDisposable];

        [disposable addDisposable:[[XPCarControlViewModel.sharedInstance currentVehicleBleConnectSignalWithTimeout:10] subscribeNext:^(id  _Nullable x) {

        } error:^(NSError * _Nullable error) {
            [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeNotNearby userInfo:@{NSLocalizedDescriptionKey: @"未检测到附近小鹏汽车，请确认", NSLocalizedRecoverySuggestionErrorKey: @"1、手机靠近车辆\n2、无其他手机/手表钥匙连接车辆，如有请断开其蓝牙，并重新检查", NSLocalizedFailureReasonErrorKey: @"请断开周围其他已授权手机/手表钥匙蓝牙后重试"}]];
        } completed:^{
            [subscriber sendNext:@(XPKeyCheckProgressConnectChecked)];
            [subscriber sendCompleted];
        }]];

        return disposable;
    }] catch:^RACSignal * _Nonnull(NSError * _Nonnull error) {
        @strongify(self);
        [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_FAIL_CONNECT_FAILED module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];

        if(tryCount == 0){
            return [RACSignal error:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeGoToFinal userInfo:@{}]];
        }

        if(tryCount == 1){
            return [self restartAppSignal];
        }

        return [[self alertControllerSignalWithTitle:error.localizedDescription message:error.localizedRecoverySuggestion buttonTitles:@[@"重新检查", @"确认，下一步"]] flattenMap:^__kindof RACSignal * _Nullable(id  _Nullable value) {
            @strongify(self);
            if([value integerValue] == 1){
                return [[self resetBleSignal] concat:[self monaCheckConnectSignalWithTryCount:tryCount-1]];
            }
            return [self monaCheckConnectSignalWithTryCount:tryCount];
        }];
    }];
}

- (RACSignal<NSNumber*> *)checkConnectSignalWithTryCount:(NSInteger)tryCount tryDelete:(BOOL)tryDelete{
    // Debug
//    return @[@(XPKeyCheckProgressConnectChecking), @(XPKeyCheckProgressConnectChecked)].rac_sequence.signal;

    @weakify(self);
    return [[RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        [subscriber sendNext:@(XPKeyCheckProgressConnectChecking)];
        @strongify(self);
        __block BOOL authFail = NO;
        RACCompoundDisposable *disposable = [RACCompoundDisposable compoundDisposable];

        RACSignal *currentBleStateSignal = [RACSignal return:@{
            XP_BLEKEY_IS_COMMUNICATE_KEY: @(YES),
            XP_BLEKEY_CONNECT_STATE_KEY: @([XPVehicleSDK bleConnectState])
        }];
        [disposable addDisposable:[[self.bleConnectStateSubject merge:currentBleStateSignal]
                                   subscribeNext:^(NSDictionary * _Nullable x){
            BOOL isCommunicate = [x[XP_BLEKEY_IS_COMMUNICATE_KEY] boolValue];
            XPBLEConnectionState state = [x[XP_BLEKEY_CONNECT_STATE_KEY] intValue];
            if (isCommunicate && state == XPBLEConnectionStateConnecting) {
                authFail = YES;
            }
        }]];

        RACSignal *bleConnectSignal = [[RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
            if ([XPVehicleSDK bleConnectState] == XPBLEConnectionStateAvailable) {
                [subscriber sendCompleted];
                return nil;
            }
            RACDisposable *disposable = [self.bleConnectStateSubject subscribeNext:^(id  _Nullable x) {
                if ([x[XP_BLEKEY_CONNECT_STATE_KEY] integerValue] == XPBLEConnectionStateAvailable) {
                    [subscriber sendCompleted];
                }
            }];
            return disposable;
        }] timeout:10 onScheduler:RACScheduler.scheduler error:[NSError errorWithDomain:XPCarControlErrorDomain code:XPCarControlErrorCodeBleNotConnected userInfo:@{}]] ;

        [disposable addDisposable:[bleConnectSignal subscribeNext:^(id  _Nullable x) {

        } error:^(NSError * _Nullable error) {
            if(authFail){
                [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeFailToAuth userInfo:@{NSLocalizedDescriptionKey: @"连接失败", NSLocalizedRecoverySuggestionErrorKey: @"尝试重新连接"}]];
            }else{
                [subscriber sendError:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeFailToConnect userInfo:@{NSLocalizedDescriptionKey: @"连接失败", NSLocalizedRecoverySuggestionErrorKey: @"尝试重新连接"}]];
            }
        } completed:^{
            [subscriber sendNext:@(XPKeyCheckProgressConnectChecked)];
            [subscriber sendCompleted];
        }]];

        return disposable;
    }] catch:^RACSignal * _Nonnull(NSError * _Nonnull error) {
        @strongify(self);

        if(error.code == XPKeyCheckErrorCodeFailToAuth){
            [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_FAIL_AUTH_FAILED module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];

            if(tryDelete){
                return [[self alertControllerSignalWithTitle:@"重建手机钥匙" message:@"将先删除、再创建手机钥匙，可解决大部分手机钥匙问题。请确保网络畅通" buttonTitles:@[@"取消", @"确认"]] flattenMap:^__kindof RACSignal * _Nullable(id  _Nullable value) {
                    @strongify(self);
                    if([value integerValue] == 0){
                        return [RACSignal error:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeCancel userInfo:@{}]];
                    }
                    [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_TRY_RECREATE_KEY module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
                    return [[self showCreateKeySignalWithNeedDelete:YES] concat:[self checkConnectSignalWithTryCount:tryCount tryDelete:NO]];
                }];
            }

            return [RACSignal error:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeGoToFinal userInfo:@{}]];
        }

        [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_FAIL_CONNECT_FAILED module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];

        if(tryCount == 0){
            return [RACSignal error:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeGoToFinal userInfo:@{}]];
        }

        if(tryCount == 1){
            return [self restartAppSignal];
        }

        return [[self resetBleSignal] concat:[self checkConnectSignalWithTryCount:tryCount-1 tryDelete:tryDelete]];
    }];
}

